// ============================================================================
// PROGRESSION DYNAMIQUE DES PILOTES (système de potentiel caché)
// ============================================================================
// Plafonds par catégorie (alignés style F1 25 — top à 95 max en F1)
var _CAT_SKILL_CAP={
  "Karting Junior":58,"Karting Senior":66,"Formule 4":74,"Formula Regional":80,
  "Formule 3":84,"Formule 2":89,"Formule 1":95,
  "Super Formula":91,"Endurance WEC":92,"IndyCar":91
};
var _CAT_CONSISTENCY_CAP={
  "Karting Junior":0.85,"Karting Senior":0.87,"Formule 4":0.88,"Formula Regional":0.89,
  "Formule 3":0.90,"Formule 2":0.91,"Formule 1":0.94,
  "Super Formula":0.91,"Endurance WEC":0.92,"IndyCar":0.91
};
var _CAT_SKILL_MIN={
  "Karting Junior":35,"Karting Senior":45,"Formule 4":52,"Formula Regional":58,
  "Formule 3":63,"Formule 2":70,"Formule 1":72,
  "Super Formula":72,"Endurance WEC":72,"IndyCar":72
};

// Calcule le delta annuel de skill basé sur âge, potentiel et croissance.
// Retourne un nombre signé (peut être négatif en cas de déclin marqué).
function _computeAnnualSkillDelta(driver){
  if(!driver)return 0;
  var sk=driver.skill||60;
  var pot=driver.pot||sk;
  var gr=driver.gr||0.8;
  var age=driver.age||25;
  var peakAge=driver.peakAge||27;
  var baseGrowth=2*gr;
  var ageFactor;
  if(age<peakAge-4)ageFactor=1.0;
  else if(age<peakAge)ageFactor=0.5;
  else if(age===peakAge)ageFactor=0.0;
  else if(age<=peakAge+4)ageFactor=-0.4;
  else ageFactor=-0.8;
  var rnd=0.7+Math.random()*0.6;
  var perfFactor=1.0;
  var delta=baseGrowth*ageFactor*rnd*perfFactor;
  // Plancher à -3 : un pilote ne peut pas perdre plus de 3 points de skill par an
  if(delta<-3)delta=-3;
  var newSk=sk+delta;
  if(newSk>pot)newSk=pot;
  return Math.round(newSk-sk);
}

function _computeAnnualConsistencyDelta(driver){
  if(!driver)return 0;
  var co=driver.consistency||0.8;
  var age=driver.age||25;
  var peakAge=driver.peakAge||27;
  var d=0;
  if(age<peakAge)d=0.005+Math.random()*0.01;
  else if(age===peakAge)d=Math.random()*0.005;
  else if(age<=peakAge+4)d=-0.005-Math.random()*0.005;
  else d=-0.01-Math.random()*0.01;
  return d;
}

// Fait progresser TOUS les pilotes du pool d'une saison.
function _progressDriverPool(){
  if(!G.driverPool)return;
  Object.keys(G.driverPool).forEach(function(id){
    var d=G.driverPool[id];
    if(!d||d.retired)return;
    d.age=(d.age||25)+1;
    var dskill=_computeAnnualSkillDelta(d);
    d.skill=Math.max(30,Math.min(99,(d.skill||60)+dskill));
    var dco=_computeAnnualConsistencyDelta(d);
    d.consistency=Math.max(0.55,Math.min(0.95,(d.consistency||0.8)+dco));
    d.consistency=Math.round(d.consistency*100)/100;
    var capSk=_CAT_SKILL_CAP[d.cat];
    if(capSk&&d.skill>capSk)d.skill=capSk;
    var capCo=_CAT_CONSISTENCY_CAP[d.cat];
    if(capCo&&d.consistency>capCo)d.consistency=capCo;
    d.seasonsInCat=(d.seasonsInCat||0)+1;
    if(d.career)d.career.seasons=(d.career.seasons||0)+1;
  });
}

// Décide si un pilote retraite (âge avancé + déclin)
function _shouldRetireDriver(d){
  if(!d||d.retired)return false;
  if(d.age>=40)return true;
  if(d.age>=37&&d.skill<78)return true;
  if(d.age>=35&&d.skill<72)return true;
  return false;
}

var _KARTING_AGE_LIMITS={"Karting Junior":15,"Karting Senior":17};
var _KARTING_PROMO_TARGET={"Karting Junior":"Karting Senior","Karting Senior":"Formule 4"};

// Génère un nouveau pilote junior pour combler une place vide
function _generateNewKartingRookie(cat){
  var firstNames=["Tom","Lucas","Hugo","Alex","Marco","Diego","Pedro","Yuki","Liam","Noah","Mateo","Andrea","Felix","Oscar","Theo","Kenji","Naoki","Ravi","Carlos","Mario"];
  var lastNames=["Martin","Dubois","Rossi","Schmidt","Garcia","Silva","Tanaka","Smith","Williams","Sato","Berg","Conti","Vargas","Park","Brown","King","Hansen","Petrov","Costa","Lefevre"];
  var nats=["FR","IT","DE","ES","BR","JP","GB","NL","SE","NO","FI","CA","US","AU","BE","AR","DK","CH","KR","PT"];
  var fn=firstNames[Math.floor(Math.random()*firstNames.length)];
  var ln=lastNames[Math.floor(Math.random()*lastNames.length)]+" "+(Math.floor(Math.random()*9000)+1000);
  var fullName=fn+" "+ln;
  var nat=nats[Math.floor(Math.random()*nats.length)];
  var baseSk=cat==="Karting Junior"?(40+Math.floor(Math.random()*15)):(48+Math.floor(Math.random()*15));
  var co=0.65+Math.random()*0.2;
  if(typeof _genHiddenAttrs!=="function")return null;
  var h=_genHiddenAttrs(baseSk,cat,fullName);
  return{
    id:h.id+"_r"+Math.floor(Math.random()*9999),
    firstName:fn,lastName:ln,name:fullName,nat:nat,
    skill:baseSk,consistency:Math.round(co*100)/100,
    pot:h.pot,gr:h.gr,peakAge:h.peakAge,
    age:cat==="Karting Junior"?(12+Math.floor(Math.random()*2)):(15+Math.floor(Math.random()*2)),
    cat:cat,team:null,retired:false,seasonsInCat:0,
    career:{wins:0,podiums:0,titles:0,seasons:0}
  };
}

// Choisit une catégorie de relégation pour un F1 vieillissant
function _pickRelegationTargetForF1(d){
  var nat=d.nat||"";
  if(nat==="JP")return "Super Formula";
  if(nat==="US")return "IndyCar";
  var pool=["Endurance WEC","IndyCar","Super Formula"];
  return pool[Math.floor(Math.random()*pool.length)];
}

// Score de promotion (skill + bonus jeunesse + bonus marge potentiel)
function _scoreForPromotion(d){
  var pot=d.pot||d.skill;
  var young=d.age<=27?1.0:0.7;
  var room=Math.max(0,pot-d.skill);
  return d.skill+0.3*room+5*young;
}

// Gère tous les mouvements inter-catégories en fin de saison.
function _handleDriverMovements(){
  if(!G.driverPool)return;
  var pool=G.driverPool;
  var ids=Object.keys(pool);

  // === Étape 1 : retraites (sauf karting qui se gère par âge) ===
  ids.forEach(function(id){
    var d=pool[id];
    if(!d||d.retired)return;
    if(d.cat==="Karting Junior"||d.cat==="Karting Senior")return;
    if(_shouldRetireDriver(d)){d.retired=true;d.team=null}
  });

  // === Étape 2 : karting — sortie par âge ===
  ["Karting Junior","Karting Senior"].forEach(function(cat){
    var ageLimit=_KARTING_AGE_LIMITS[cat];
    var target=_KARTING_PROMO_TARGET[cat];
    ids.forEach(function(id){
      var d=pool[id];
      if(!d||d.retired||d.cat!==cat)return;
      if(d.age>ageLimit){
        var nextCap=_CAT_SKILL_CAP[target]||78;
        var goodEnough=d.skill>=(_CAT_SKILL_CAP[cat]-8)&&d.pot>=(nextCap-10);
        if(goodEnough){
          d.cat=target;
          d.seasonsInCat=0;
          d.team=null;
          d.skill=Math.max(_CAT_SKILL_MIN[target]||50,d.skill-2);
        } else {
          d.retired=true;
          d.team=null;
        }
      }
    });
  });

  // === Étape 3 : F1 → relégation des très vieux/très en déclin ===
  ids.forEach(function(id){
    var d=pool[id];
    if(!d||d.retired||d.cat!=="Formule 1")return;
    if(d.age>=33&&d.skill<78){
      var tgt=_pickRelegationTargetForF1(d);
      d.cat=tgt;
      d.seasonsInCat=0;
      d.team=null;
    }
  });

  // === Étape 4 : promotions inter-catégories ===
  function _activeInCat(cat){
    return Object.keys(pool).filter(function(id){return pool[id].cat===cat&&!pool[id].retired}).length;
  }
  function _topCandidatesFor(srcCat,n){
    var candidates=Object.keys(pool).map(function(id){return pool[id]})
      .filter(function(d){return d.cat===srcCat&&!d.retired});
    candidates.sort(function(a,b){return _scoreForPromotion(b)-_scoreForPromotion(a)});
    return candidates.slice(0,n);
  }

  var TARGET_GRID={"Formule 1":20,"Formule 2":22,"Formule 3":29,
    "Formula Regional":27,"Formule 4":29,"Karting Senior":35,"Karting Junior":29,
    "Super Formula":19,"Endurance WEC":29,"IndyCar":23};
  var PROMO_SOURCES={
    "Formule 1":["Formule 2"],
    "Formule 2":["Formule 3"],
    "Formule 3":["Formula Regional"],
    "Formula Regional":["Formule 4"],
    "Formule 4":["Karting Senior"],
    "Super Formula":["Formule 2","Formule 3"],
    "Endurance WEC":["Formule 2","Formule 1"],
    "IndyCar":["Formule 2","Formule 1"]
  };
  var MAX_PROMO_PER_CAT={"Formule 1":3,"Formule 2":3,"Formule 3":3,
    "Formula Regional":3,"Formule 4":3,"Super Formula":2,"Endurance WEC":2,"IndyCar":2};

  // Process top → bottom (F1 d'abord)
  ["Formule 1","Formule 2","Formule 3","Formula Regional","Formule 4",
   "Super Formula","Endurance WEC","IndyCar"].forEach(function(targetCat){
    var sources=PROMO_SOURCES[targetCat]||[];
    if(!sources.length)return;
    var current=_activeInCat(targetCat);
    var target=TARGET_GRID[targetCat]||20;
    var slots=Math.max(0,target-current);
    if(slots<=0)return;
    var maxPromo=MAX_PROMO_PER_CAT[targetCat]||3;
    // Mode "urgence" si crise majeure (slots>=6 → +4 de marge sur potDelta)
    var potDelta=slots>=6?8:slots>=4?6:4;
    var minPotForTarget=Math.max(70,(_CAT_SKILL_CAP[targetCat]||80)-potDelta);
    var promoted=0;
    sources.forEach(function(srcCat){
      if(promoted>=maxPromo)return;
      var cands=_topCandidatesFor(srcCat,12).filter(function(d){
        return d.pot>=minPotForTarget&&d.age>=(targetCat==="Formule 1"?18:16);
      });
      cands.forEach(function(d){
        if(promoted>=maxPromo||promoted>=slots)return;
        d.cat=targetCat;
        d.seasonsInCat=0;
        d.team=null;
        d.skill=Math.max(_CAT_SKILL_MIN[targetCat]||60,d.skill-1);
        promoted++;
      });
    });
  });

  // === Étape 5 : limite d'âge transition (pilotes qui stagnent en cat junior trop longtemps) ===
  var TRANS_AGE_LIMITS={"Formule 4":22,"Formula Regional":24,"Formule 3":26,"Formule 2":29};
  Object.keys(TRANS_AGE_LIMITS).forEach(function(cat){
    var maxAge=TRANS_AGE_LIMITS[cat];
    ids.forEach(function(id){
      var d=pool[id];
      if(!d||d.retired||d.cat!==cat)return;
      if(d.age>=maxAge){
        d.retired=true;
        d.team=null;
      }
    });
  });

  // === Étape 6 : régénération de rookies ===
  ["Karting Junior","Karting Senior"].forEach(function(cat){
    var current=_activeInCat(cat);
    var target=TARGET_GRID[cat]||29;
    var missing=Math.max(0,target-current);
    if(missing>0){
      var maxNew=Math.min(missing,Math.floor(target*0.3));
      for(var i=0;i<maxNew;i++){
        var rookie=_generateNewKartingRookie(cat);
        if(rookie&&pool[rookie.id]===undefined)pool[rookie.id]=rookie;
      }
    }
  });

  // Cap de SF/WEC/IndyCar pour éviter gonflement
  ["Super Formula","Endurance WEC","IndyCar"].forEach(function(cat){
    var current=_activeInCat(cat);
    var target=TARGET_GRID[cat]||25;
    if(current>target+3){
      // Pousser les plus âgés à la retraite
      var sorted=Object.keys(pool).map(function(id){return pool[id]})
        .filter(function(d){return d.cat===cat&&!d.retired})
        .sort(function(a,b){return (b.age||0)-(a.age||0)});
      var toRetire=current-target-2;
      for(var i=0;i<toRetire&&i<sorted.length;i++){
        sorted[i].retired=true;
        sorted[i].team=null;
      }
    }
  });
}

